where scene_id in (select scene_id from tmp_reset_scene_ids);

delete from cost_rule_tier
where scene_id in (select scene_id from tmp_reset_scene_ids);

delete from cost_rule_condition
where scene_id in (select scene_id from tmp_reset_scene_ids);

delete from cost_rule
where scene_id in (select scene_id from tmp_reset_scene_ids);

